#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long S, A, B; int C; scanf("%lld %lld %lld %d", &S, &A, &B, &C);
        double final = S * (100.0 + C) / 100.0;
        const double eps = 1e-9;
        if(final + eps >= A && final - eps <= B) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

