import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    eps = 1e-9
    for _ in range(T):
        S = int(next(it)); A = int(next(it)); B = int(next(it)); C = int(next(it))
        final_price = S * (100.0 + C) / 100.0
        if final_price + eps >= A and final_price - eps <= B:
            out.append("YES")
        else:
            out.append("NO")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

